using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x = 0, f = 1;
		char ch = gc();
		wh(ch < '0' || ch > '9')
		{
			if (ch == '-')f = -1;
			ch = getchar();
		}
		wh(ch >= '0' && ch <= '9')
		{
			x = x * 10 + ch - '0';
			ch = gc();
		}
		return x * f;
	}
	void write(ll x)
	{
		if (x < 0)pc('-'), x = -x;
		if (x > 9)write(x / 10);
		pc(x % 10 + '0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
int n, a[2005], b[2005], t, c, m, q, cnt = 0, l;
signed main(void)
{
	cin >> n;
	for (int i = 1; i <= n; i++)
	{
		cin >> a[i];
	}
	for (int i = 1; i <= n; i++)
	{
		cin >> b[i];
	}
	m = n;
	q = n;
	sort(a + 1, a + n + 1);
	sort(b + 1, b + n + 1);
	while (t <= m)
	{
		if (a[m] > b[q])
		{
			cnt++;
			m--;
			q--;
		}
		else if (a[t] > b[c])
		{
			cnt++;
			t++;
			c++;
		}
		else
		{
			if (a[t] < b[q])
			{
				cnt--;
			}
			t++;
			q--;
		}
	}
	cout << cnt * 200 - 200;
	return false; 
}
